package main

import (
	"strings"
)

func solve(words []string) []int64 {
	n := len(words)
	answer := make([]int64, n)

	// Build a trie to store the words
	type TrieNode struct {
		children map[rune]*TrieNode
	}
	root := &TrieNode{children: make(map[rune]*TrieNode)}

	// Build the trie
	for _, word := range words {
		node := root
		for _, c := range word {
			if _, exists := node.children[c]; !exists {
				node.children[c] = &TrieNode{children: make(map[rune]*TrieNode)}
			}
			node = node.children[c]
		}
	}

	// Function to find the longest common prefix between two words
	lcp := func(a, b string) int {
		minLen := min(len(a), len(b))
		for i := 0; i < minLen; i++ {
			if a[i] != b[i] {
				return i
			}
		}
		return minLen
	}

	// For each index, simulate removing it and compute the answer
	for i := 0; i < n; i++ {
		// Create a new list without the i-th element
		newWords := append(words[:i], words[i+1:]...)
		maxLcp := 0

		// Compute the maximum LCP between adjacent pairs
		for j := 0; j < len(newWords)-1; j++ {
			currentLcp := lcp(newWords[j], newWords[j+1])
			if currentLcp > maxLcp {
				maxLcp = currentLcp
			}
		}

		answer[i] = int64(maxLcp)
	}

	return answer
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}
